// src/pages/SellerDashboard.js
import React, { useState } from "react";
import "./SellerDashboard.css"; // custom css file
function SellerDashboard() {
  const [products, setProducts] = useState([]);
  const [form, setForm] = useState({
    name: "",
    description: "",
    category: "Earphone",
    price: "",
    offerPrice: "",
  });

  const handleChange = (e) => {
    setForm({ ...form, [e.target.name]: e.target.value });
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    setProducts([...products, form]);
    setForm({ name: "", description: "", category: "Earphone", price: "", offerPrice: "" });
  };

  return (
    <div className="seller-dashboard">
      {/* Sidebar */}
      <aside className="sidebar">
        <h1 className="logo"></h1>
        <nav>
          <ul>
            <li className="active">➕ Add Product</li>
            <li>📦 Product List</li>
            <li>📝 Orders</li>
          </ul>
        </nav>
      </aside>

      {/* Main Content */}
      <main className="main-content">
        <h2 className="page-title">Add Product</h2>

        {/* Form */}
        <form className="product-form" onSubmit={handleSubmit}>
          {/* Upload section */}
         <div className="upload-section">
  {[0, 1, 2].map(i => (
    <UploadBox
      key={i}
      index={i}
      image={images[i]}
      onChange={(e) => handleFileChange(e, i)}
    />
  ))}
</div>

          <label>Product Name</label>
          <input
            type="text"
            name="name"
            placeholder="Type here"
            value={form.name}
            onChange={handleChange}
            required
          />

          <label>Product Description</label>
          <textarea
            name="description"
            placeholder="Type here"
            value={form.description}
            onChange={handleChange}
          ></textarea>

          <div className="row">
            <div>
              <label>Category</label>
              <select name="category" value={form.category} onChange={handleChange}>
                <option>Earphone</option>
                <option>Smartphone</option>
                <option>Laptop</option>
                <option>Smartwatch</option>
                <option>Other</option>
              </select>
            </div>

            <div>
              <label>Product Price</label>
              <input
                type="number"
                name="price"
                placeholder="0"
                value={form.price}
                onChange={handleChange}
                required
              />
            </div>

            <div>
              <label>Offer Price</label>
              <input
                type="number"
                name="offerPrice"
                placeholder="0"
                value={form.offerPrice}
                onChange={handleChange}
              />
            </div>
          </div>

          <button type="submit" className="add-btn">ADD</button>
        </form>

        {/* Seller's products */}
        <h3 className="list-title">Your Listed Items</h3>
        <div className="product-list">
          {products.map((p, idx) => (
            <div key={idx} className="product-card">
              <h4>{p.name}</h4>
              <p>{p.description}</p>
              <p><b>Category:</b> {p.category}</p>
              <p><b>Price:</b> ₹{p.price}</p>
              {p.offerPrice && <p><b>Offer:</b> ₹{p.offerPrice}</p>}
            </div>
          ))}
        </div>
      </main>
    </div>
  );
}

export default SellerDashboard;
